// ── TIER ALGORITHM ────────────────────────────────────────────────────────────
// COLE decides the tier — the buyer never chooses in the popup
// Rule: $67 only for SAFE/CLEAR outcomes. ANY risk = $147.

function recommendedTier(
  bracketStatus: BracketStatus,
  priorResidency: number | string,
  currentCountries: number | string,
  hasPermanentHome: number | string,
  workType: number | string,
  citizenship: number | string,
): PackTier {
  // Dual residency OR US citizen OR constantly moving OR multi-country work → tier2. Otherwise tier1.
    if (currentCountries === 'moving' || citizenship === 'us' || hasPermanentHome === 'multi' || workType === 'mixed' || workType === 'business') return 147;
  // Default: safe = $67, any risk = $147
  return (bracketStatus === "clear" || bracketStatus === "out_of_scope" || bracketStatus === "pass")
    ? 67
    : 147;
}

